document.addEventListener("DOMContentLoaded",function(){let mySwiper=null,currentMode=null;function getSwiperOptions(isDesktop){const baseOptions={loop:true,grabCursor:true,allowTouchMove:true,slideToClickedSlide:true,keyboard:{enabled:true,onlyInViewport:true},pagination:{el:".slider_pagination",clickable:true,dynamicBullets:true,dynamicMainBullets:1},breakpoints:{992:{slidesPerView:3,spaceBetween:86},480:{slidesPerView:2,spaceBetween:32},0:{slidesPerView:1,spaceBetween:0}},on:{init:function(){fixSwiperA11y(this)},slideChange:function(){fixSwiperA11y(this)}}};if(isDesktop){baseOptions.freeMode={enabled:true,sticky:false};baseOptions.mousewheel={enabled:true,forceToAxis:true}}return baseOptions}function initSwiper(){const isDesktop=window.innerWidth>=992,newMode=isDesktop?"desktop":"mobile";if(newMode===currentMode)return;if(mySwiper){mySwiper.destroy(true,true);mySwiper=null}mySwiper=new Swiper(".slider_component",getSwiperOptions(isDesktop));currentMode=newMode}function fixSwiperA11y(swiper){if(swiper.wrapperEl){swiper.wrapperEl.removeAttribute("role")}swiper.slides.forEach(slide=>{slide.removeAttribute("role")})}initSwiper();let resizeTimeout;window.addEventListener("resize",function(){clearTimeout(resizeTimeout);resizeTimeout=setTimeout(initSwiper,200)})});
